xlimits(-8,8); ylimits(-1,10);
xaxis(Label("$x$"),-8,8,EndArrow(size=5));
yaxis(Label("$y$"),-2,8,EndArrow(size=5));
dot("$A(6,6)$",(6,6)); dot("$B(-6,6)$",(-6,6),W); dot("$O$",(0,0),SW);
